args.sparql:
SELECT ?medal WHERE { 
  wd:Q17299929 wdt:P31 wd:Q11446 .
  ?event wdt:P361 wd:Q17299929 ;
         wdt:P641 wd:Q55244942 .
  ?athlete p:P1188 ?participation .
  ?participation ps:P1188 ?event ;
                 pq:P2593 "8:37.51" ;
                 pq:P1617 ?rank .
  BIND(CASE 
         WHEN ?rank = 1 THEN "gold"
         WHEN ?rank = 2 THEN "silver"
         WHEN ?rank = 3 THEN "bronze"
       END AS ?medal)
  FILTER(?medal != "")
}

SELECT ?athlete ?time ?rank WHERE {
  ?event wdt:P361 wd:Q17299929 ; # part of the championships
         wdt:P641 wd:Q55244942 . # men's 3000m steeplechase
  ?athlete p:P1188 ?participation .
  ?participation ps:P1188 ?event ;
                 pq:P2027 "8:37.51" ;
                 pq:P1344 ?rank .
}

SELECT ?medal WHERE {
  ?event wdt:P361 wd:Q17299929 ; # event part of 2014 Championships
         wdt:P641 wd:Q55244942 . # sport: men's 3000m steeplechase
  ?athlete p:P1188 ?participation .
  ?participation ps:P1188 ?event ;
                 pq:P2027 "8:37.51" ;
                 pq:P1344 ?rank .
  VALUES (?rank ?medal) {
    ("1" "gold")
    ("2" "silver")
    ("3" "bronze")
  }
}

SELECT ?time ?rank WHERE {
  wd:Q1679 p:P1188 ?participation .
  ?participation ps:P1188 ?event ;
                 pq:P2781 ?time ;
                 pq:P1344 ?rank .
  ?event wdt:P361 wd:Q17299929 ;
         wdt:P641 wd:Q55244942 .
}

SELECT ?event ?qualPropLabel ?qualValLabel WHERE {
  wd:Q1679 p:P1188 ?participation .
  ?participation ps:P1188 ?event ;
                 ?qualProp ?qualVal .
  ?qualProp rdfs:label ?qualPropLabel .
  ?qualVal rdfs:label ?qualValLabel .
  FILTER(LANG(?qualPropLabel) = 'en' && LANG(?qualValLabel) = 'en')
}
LIMIT 10

SELECT ?medal WHERE {
  BIND("gold" AS ?medal)
  FILTER EXISTS {
    wd:Q17299929 wdt:P31 wd:Q11446 .
    wd:Q17299929 wdt:P641 wd:Q55244942 .
    wd:Q1679 p:P1188 ?participation .
    ?participation ps:P1188 wd:Q17501630 ;
                   pq:P2781 ?time .
    FILTER(?time = "8:37.51")
    ?participation pq:P1344 "1" .
  }
}
